window.MM = window.MM || {};
window.MM["psych_p2_behav"] = [
  {q:"In classical conditioning, a previously neutral stimulus becomes capable of eliciting a response after being repeatedly paired with a stimulus that naturally produces that response. What is the term for the originally neutral stimulus after conditioning occurs?",o:["Unconditioned stimulus", "Unconditioned response", "Conditioned stimulus", "Reinforcer"],a:2,e:"After pairing with the unconditioned stimulus, the previously neutral stimulus becomes a conditioned stimulus capable of eliciting the conditioned response."},
  {q:"A medical student feels anxious whenever entering the examination hall because previous exams were stressful. The exam hall has become associated with anxiety. Which learning process best explains this phenomenon?",o:["Operant conditioning", "Classical conditioning", "Observational learning", "Insight learning"],a:1,e:"Classical conditioning occurs when a neutral stimulus (exam hall) becomes associated with an emotional response (anxiety) after repeated pairing with stressful experiences."},
  {q:"In Pavlov’s experiment, the food presented to dogs that naturally produced salivation is called the:",o:["Conditioned stimulus", "Conditioned response", "Neutral stimulus", "Unconditioned stimulus"],a:3,e:"The unconditioned stimulus naturally triggers a response without prior learning. In Pavlov’s experiment, food produced salivation automatically."},
  {q:"A child receives praise from parents whenever she completes homework on time. Over time, she begins completing homework regularly to obtain praise. Which learning principle explains this behavior?",o:["Classical conditioning", "Operant conditioning", "Latent learning", "Imprinting"],a:1,e:"Operant conditioning involves behavior shaped by consequences. Praise acts as positive reinforcement increasing the likelihood of repeating the behavior."},
  {q:"In classical conditioning, the learned reaction that occurs after conditioning to the conditioned stimulus is known as the:",o:["Conditioned response", "Unconditioned response", "Reflex response", "Spontaneous recovery"],a:0,e:"The conditioned response is the learned response that occurs when the conditioned stimulus is presented."},
  {q:"A medical intern studies hard because previous poor exam results resulted in criticism from supervisors. Avoiding criticism motivates studying. Which type of reinforcement is involved?",o:["Positive reinforcement", "Positive punishment", "Negative reinforcement", "Extinction"],a:2,e:"Negative reinforcement increases behavior by removing or avoiding an unpleasant stimulus."},
  {q:"In Pavlov’s classical conditioning experiment, the bell that initially did not produce salivation in dogs before pairing with food is referred to as the:",o:["Conditioned response", "Unconditioned stimulus", "Neutral stimulus", "Reinforcer"],a:2,e:"A neutral stimulus initially produces no response until it becomes associated with an unconditioned stimulus."},
  {q:"A child learns to say “thank you” because parents reward the behavior with smiles and approval. Which concept explains the strengthening of this behavior?",o:["Negative reinforcement", "Positive reinforcement", "Classical conditioning", "Extinction"],a:1,e:"Positive reinforcement strengthens behavior by presenting a pleasant stimulus after the behavior."},
  {q:"In classical conditioning, when a conditioned stimulus is repeatedly presented without the unconditioned stimulus, the conditioned response gradually weakens. This process is called:",o:["Generalization", "Discrimination", "Shaping", "Extinction"],a:3,e:"Extinction occurs when the conditioned stimulus no longer predicts the unconditioned stimulus."},
  {q:"A patient develops nausea whenever entering a hospital because previous chemotherapy treatments caused severe nausea. Which type of conditioning explains this reaction?",o:["Operant conditioning", "Insight learning", "Classical conditioning", "Latent learning"],a:2,e:"The hospital becomes a conditioned stimulus associated with nausea, producing anticipatory nausea."},
  {q:"In operant conditioning, behavior that is strengthened by the presentation of a pleasant stimulus is called:",o:["Negative reinforcement", "Punishment", "Positive reinforcement", "Extinction"],a:2,e:"Positive reinforcement increases behavior by presenting a rewarding stimulus after the behavior."},
  {q:"A child stops touching a hot stove after experiencing pain from touching it previously. Which learning principle explains this change in behavior?",o:["Positive reinforcement", "Negative reinforcement", "Classical conditioning", "Punishment"],a:3,e:"Punishment reduces the likelihood of repeating a behavior by introducing an unpleasant consequence."},
  {q:"In classical conditioning, the process by which stimuli similar to the conditioned stimulus also produce the conditioned response is called:",o:["Discrimination", "Generalization", "Extinction", "Reinforcement"],a:1,e:"Generalization occurs when similar stimuli trigger the same conditioned response."},
  {q:"A child learns to clean his room because parents gradually reward closer approximations to the desired behavior. Which learning technique is being used?",o:["Punishment", "Shaping", "Extinction", "Insight learning"],a:1,e:"Shaping reinforces successive approximations of the desired behavior until the full behavior is achieved."},
  {q:"In operant conditioning, removing an unpleasant stimulus after a desired behavior increases the likelihood of that behavior recurring. This is called:",o:["Positive reinforcement", "Positive punishment", "Negative reinforcement", "Extinction"],a:2,e:"Negative reinforcement strengthens behavior by removing an unpleasant stimulus."},
  {q:"A dog salivates when hearing a bell previously paired with food. The salivation in response to the bell is the:",o:["Unconditioned response", "Neutral response", "Reinforcement", "Conditioned response"],a:3,e:"The conditioned response is the learned reaction to the conditioned stimulus."},
  {q:"In operant conditioning, a behavior decreases because a positive stimulus is removed following that behavior. This is called:",o:["Positive reinforcement", "Negative reinforcement", "Negative punishment", "Extinction"],a:2,e:"Negative punishment decreases behavior by removing a pleasant stimulus."},
  {q:"A patient who once experienced food poisoning from seafood develops nausea when smelling seafood. Which conditioning concept explains this learned association?",o:["Operant conditioning", "Social learning", "Classical conditioning", "Insight learning"],a:2,e:"Conditioned taste aversion is a form of classical conditioning."},
  {q:"The psychologist most closely associated with the concept of operant conditioning is:",o:["Ivan Pavlov", "B.F. Skinner", "Jean Piaget", "Sigmund Freud"],a:1,e:"B.F. Skinner developed the theory of operant conditioning."},
  {q:"In operant conditioning, reinforcement schedules that reward behavior after an unpredictable number of responses are called:",o:["Fixed ratio schedules", "Fixed interval schedules", "Continuous schedules", "Variable ratio schedules"],a:3,e:"Variable ratio schedules produce high and steady response rates."},
  {q:"Classical conditioning primarily involves learning through:",o:["Cognitive reasoning", "Observation of others", "Association between stimuli", "Insight"],a:2,e:"Classical conditioning involves forming associations between stimuli."},
  {q:"A child learns to fear dogs after being bitten by one. Which psychological mechanism explains this learning?",o:["Operant conditioning", "Classical conditioning", "Latent learning", "Observational learning"],a:1,e:"Fear becomes associated with dogs through classical conditioning."},
  {q:"In classical conditioning, the stimulus that naturally produces a response without prior learning is called the:",o:["Neutral stimulus", "Conditioned stimulus", "Unconditioned stimulus", "Reinforcer"],a:2,e:"The unconditioned stimulus naturally produces a response."},
  {q:"A teacher gives students stickers whenever they answer questions correctly, increasing participation. Which principle explains this?",o:["Negative reinforcement", "Positive reinforcement", "Extinction", "Punishment"],a:1,e:"Positive reinforcement strengthens behavior through rewards."},
  {q:"The gradual disappearance of a conditioned response when the conditioned stimulus is presented repeatedly without reinforcement is known as:",o:["Discrimination", "Reinforcement", "Generalization", "Extinction"],a:3,e:"Extinction weakens learned responses when reinforcement stops."},
  {q:"In operant conditioning, punishment is intended to:",o:["Increase behavior", "Decrease behavior", "Maintain behavior", "Generalize behavior"],a:1,e:"Punishment decreases the probability of a behavior recurring."},
  {q:"A rat receives food after pressing a lever every third time. Which reinforcement schedule is this?",o:["Variable interval schedule", "Fixed interval schedule", "Fixed ratio schedule", "Variable ratio schedule"],a:2,e:"Fixed ratio schedules reinforce behavior after a set number of responses."},
  {q:"The reappearance of a previously extinguished conditioned response after a rest period is known as:",o:["Reinforcement", "Spontaneous recovery", "Discrimination", "Shaping"],a:1,e:"Spontaneous recovery occurs after extinction when the response returns following a rest period."},
  {q:"Learning in which behavior changes due to observing others is known as:",o:["Classical conditioning", "Operant conditioning", "Observational learning", "Insight learning"],a:2,e:"Observational learning occurs through watching and imitating others."},
  {q:"Which psychologist first described classical conditioning through experiments with dogs?",o:["B.F. Skinner", "Albert Bandura", "Ivan Pavlov", "John Watson"],a:2,e:"Ivan Pavlov discovered classical conditioning through experiments with dogs."},
  {q:"In classical conditioning, the ability to distinguish between similar stimuli and respond only to the conditioned stimulus is called:",o:["Generalization", "Discrimination", "Reinforcement", "Extinction"],a:1,e:"Discrimination involves differentiating between stimuli."},
  {q:"A behavior followed by a reward becomes more likely to occur again. Which principle explains this?",o:["Punishment", "Extinction", "Generalization", "Reinforcement"],a:3,e:"Reinforcement strengthens behavior."},
  {q:"A child receives pocket money occasionally for good behavior, making the reward unpredictable. Which schedule is this?",o:["Fixed interval schedule", "Continuous reinforcement", "Fixed ratio schedule", "Variable ratio schedule"],a:3,e:"Variable ratio schedules reinforce behavior unpredictably and strongly maintain behavior."},
  {q:"In operant conditioning, giving a child extra chores for misbehavior is an example of:",o:["Negative reinforcement", "Positive reinforcement", "Positive punishment", "Extinction"],a:2,e:"Positive punishment introduces an unpleasant consequence to reduce behavior."},
  {q:"A child learns that studying results in good grades and praise. Which learning principle explains repeated studying behavior?",o:["Extinction", "Discrimination", "Reinforcement", "Insight learning"],a:2,e:"Reinforcement strengthens behavior through positive outcomes."},
  {q:"Classical conditioning primarily explains learning related to:",o:["Voluntary behaviors", "Insightful reasoning", "Abstract thinking", "Reflexive responses"],a:3,e:"Classical conditioning mainly involves automatic reflexive responses."},
  {q:"In operant conditioning, reinforcement given after every correct response is called:",o:["Variable ratio reinforcement", "Fixed interval reinforcement", "Continuous reinforcement", "Partial reinforcement"],a:2,e:"Continuous reinforcement occurs when every correct response is rewarded."},
  {q:"The psychologist who applied classical conditioning principles to human behavior and emotions was:",o:["Jean Piaget", "Erik Erikson", "Lawrence Kohlberg", "John Watson"],a:3,e:"John Watson demonstrated classical conditioning in humans in the Little Albert experiment."},
  {q:"A behavior decreases because reinforcement is no longer provided. Which concept explains this?",o:["Extinction", "Reinforcement", "Discrimination", "Generalization"],a:0,e:"Extinction occurs when reinforcement stops and the behavior gradually disappears."},
  {q:"In conditioning theory, learning occurs primarily through:",o:["Genetic inheritance", "Association and consequences", "Intuition alone", "Random behavior"],a:1,e:"Conditioning theories explain learning through associations between stimuli and consequences of behavior."},
  {q:"Which psychological perspective emphasizes mental processes such as thinking, memory, perception, and problem-solving in explaining behavior?",o:["Behaviorism", "Psychoanalytic theory", "Humanistic psychology", "Cognitive psychology"],a:3,e:"Cognitive psychology focuses on internal mental processes such as perception, attention, memory, reasoning, and problem-solving."},
  {q:"A medical student remembers complex pharmacology information by organizing drugs into categories such as mechanism of action and side effects. Which cognitive strategy is being used?",o:["Classical conditioning", "Chunking", "Extinction", "Generalization"],a:1,e:"Chunking involves grouping information into meaningful units, improving memory capacity and recall."},
  {q:"According to cognitive psychology, memory that temporarily holds information for immediate processing is called:",o:["Long-term memory", "Sensory memory", "Short-term memory", "Procedural memory"],a:2,e:"Short-term memory (working memory) temporarily stores information for immediate processing and manipulation."},
  {q:"A student solving a difficult clinical case suddenly experiences a realization of the correct diagnosis without step-by-step reasoning. Which cognitive process best explains this?",o:["Classical conditioning", "Insight learning", "Reinforcement learning", "Habituation"],a:1,e:"Insight learning involves sudden understanding of a problem’s solution without gradual trial-and-error learning."},
  {q:"The process by which information from the environment is initially detected and briefly stored before further processing is called:",o:["Long-term memory", "Procedural memory", "Declarative memory", "Sensory memory"],a:3,e:"Sensory memory briefly holds sensory input from the environment before transferring it to short-term memory."},
  {q:"A patient remembers how to ride a bicycle even after many years without practice. Which type of memory explains this ability?",o:["Episodic memory", "Semantic memory", "Procedural memory", "Sensory memory"],a:2,e:"Procedural memory stores motor skills and habits that can be performed automatically once learned."},
  {q:"Which cognitive process involves interpreting sensory information to understand the environment?",o:["Conditioning", "Reinforcement", "Perception", "Motivation"],a:2,e:"Perception organizes and interprets sensory input, allowing individuals to understand and respond to their surroundings."},
  {q:"A student remembers a historical fact by relating it to an existing concept already stored in memory. Which cognitive process is involved?",o:["Classical conditioning", "Encoding through elaboration", "Extinction", "Reinforcement"],a:1,e:"Elaborative encoding improves memory by linking new information with existing knowledge."},
  {q:"According to the information-processing model, which stage of memory has the largest storage capacity and longest duration?",o:["Sensory memory", "Short-term memory", "Working memory", "Long-term memory"],a:3,e:"Long-term memory can store vast amounts of information for extended periods, potentially for a lifetime."},
  {q:"A doctor recalls a specific patient encounter from years ago during medical training. Which type of memory is involved?",o:["Procedural memory", "Semantic memory", "Episodic memory", "Working memory"],a:2,e:"Episodic memory stores personal experiences and events associated with specific contexts."},
  {q:"Which cognitive psychologist is most closely associated with the theory of cognitive development in children?",o:["Ivan Pavlov", "Jean Piaget", "B.F. Skinner", "Sigmund Freud"],a:1,e:"Jean Piaget proposed stages of cognitive development describing how children develop reasoning abilities."},
  {q:"A person recognizes a familiar face in a crowd even though they cannot recall the person’s name. Which cognitive process allows identification of the face?",o:["Recall memory", "Recognition memory", "Conditioning", "Reinforcement"],a:1,e:"Recognition memory involves identifying previously encountered information when cues are present."},
  {q:"Which type of long-term memory stores general knowledge and facts about the world?",o:["Episodic memory", "Procedural memory", "Semantic memory", "Sensory memory"],a:2,e:"Semantic memory contains factual knowledge, concepts, and language independent of personal experience."},
  {q:"A student repeatedly rehearses a phone number in order to remember it until dialing. Which cognitive process is being used?",o:["Classical conditioning", "Maintenance rehearsal", "Punishment", "Habituation"],a:1,e:"Maintenance rehearsal involves repeating information to keep it active in short-term memory."},
  {q:"A patient remembers how to perform surgical suturing learned years ago during medical training. Which memory system supports this skill?",o:["Episodic memory", "Semantic memory", "Sensory memory", "Procedural memory"],a:3,e:"Procedural memory stores motor skills and habits that are performed automatically once learned."},
  {q:"Which cognitive process allows individuals to focus on specific stimuli while ignoring irrelevant information?",o:["Generalization", "Reinforcement", "Selective attention", "Conditioning"],a:2,e:"Selective attention allows individuals to concentrate on relevant stimuli while filtering distractions."},
  {q:"A student studies information in a meaningful context and therefore remembers it better during exams. Which cognitive principle explains this improvement?",o:["Punishment", "Conditioning", "Meaningful encoding", "Habituation"],a:2,e:"Meaningful encoding strengthens memory by linking new information to existing knowledge structures."},
  {q:"The cognitive process of retrieving stored information from memory is called:",o:["Encoding", "Storage", "Consolidation", "Retrieval"],a:3,e:"Retrieval refers to accessing stored information from long-term memory."},
  {q:"A child learns that objects continue to exist even when they are out of sight. According to Piaget, this concept is called:",o:["Conservation", "Egocentrism", "Object permanence", "Reversibility"],a:2,e:"Object permanence develops during Piaget’s sensorimotor stage and reflects understanding that objects exist even when unseen."},
  {q:"In cognitive psychology, the mental framework used to organize knowledge and guide information processing is known as a:",o:["Stimulus", "Schema", "Reflex", "Reinforcer"],a:1,e:"Schemas are mental frameworks used to organize knowledge and interpret new information."},
  {q:"Which memory process involves converting information into a form suitable for storage in memory?",o:["Retrieval", "Recall", "Encoding", "Recognition"],a:2,e:"Encoding transforms sensory input into a form that can be stored in memory systems."},
  {q:"A student remembers the meaning of a medical term but cannot recall where they learned it. Which type of memory is involved?",o:["Episodic memory", "Procedural memory", "Sensory memory", "Semantic memory"],a:3,e:"Semantic memory stores factual knowledge independent of personal experiences."},
  {q:"When new information interferes with the recall of previously learned information, this phenomenon is known as:",o:["Positive reinforcement", "Extinction", "Retroactive interference", "Generalization"],a:2,e:"Retroactive interference occurs when newly learned information disrupts recall of previously learned material."},
  {q:"A student solving a complex math problem step by step is using which cognitive process?",o:["Conditioning", "Analytical reasoning", "Reinforcement", "Habituation"],a:1,e:"Analytical reasoning involves systematic logical thinking used in problem solving."},
  {q:"In cognitive theory, mental images and symbolic representations are used in:",o:["Classical conditioning", "Operant conditioning", "Mental representation", "Reinforcement"],a:2,e:"Mental representation allows individuals to manipulate symbolic images or concepts mentally."},
  {q:"A doctor recalls a clinical protocol learned years ago during training. Which type of memory retrieval is involved?",o:["Recognition", "Conditioning", "Recall", "Reinforcement"],a:2,e:"Recall involves retrieving information without external cues."},
  {q:"Which cognitive process allows people to solve problems using previous experiences?",o:["Extinction", "Punishment", "Reinforcement", "Reasoning"],a:3,e:"Reasoning allows individuals to apply prior knowledge to new situations."},
  {q:"A person remembers a childhood birthday party including location and events. Which memory system stores this information?",o:["Semantic memory", "Procedural memory", "Episodic memory", "Working memory"],a:2,e:"Episodic memory stores personal life experiences including their context."},
  {q:"Which cognitive function involves maintaining and manipulating information temporarily during problem solving?",o:["Long-term memory", "Sensory memory", "Working memory", "Procedural memory"],a:2,e:"Working memory temporarily holds and manipulates information required for reasoning and decision making."},
  {q:"The ability to solve problems creatively by viewing situations in new ways is known as:",o:["Conditioning", "Reinforcement", "Insight", "Punishment"],a:2,e:"Insight involves sudden understanding that allows creative problem solving."},
  {q:"Which cognitive process involves organizing information into meaningful categories to improve memory?",o:["Punishment", "Conditioning", "Chunking", "Extinction"],a:2,e:"Chunking groups information into meaningful units to improve memory capacity."},
  {q:"The stage of memory where information is first processed briefly after perception is called:",o:["Working memory", "Long-term memory", "Sensory memory", "Procedural memory"],a:2,e:"Sensory memory briefly stores incoming sensory information before further processing."},
  {q:"Which cognitive process allows individuals to adapt existing knowledge to new experiences?",o:["Reinforcement", "Conditioning", "Accommodation", "Habituation"],a:2,e:"In Piaget’s theory, accommodation modifies existing schemas to incorporate new information."},
  {q:"When old memories interfere with learning new information, this is called:",o:["Retroactive interference", "Reinforcement", "Proactive interference", "Extinction"],a:2,e:"Proactive interference occurs when previously learned information disrupts new learning."},
  {q:"Which cognitive process helps individuals understand relationships between concepts?",o:["Conditioning", "Punishment", "Concept formation", "Habituation"],a:2,e:"Concept formation allows individuals to categorize information and understand relationships among ideas."},
  {q:"The ability to mentally manipulate information while performing tasks is known as:",o:["Sensory memory", "Working memory", "Procedural memory", "Episodic memory"],a:1,e:"Working memory temporarily stores and manipulates information during cognitive tasks."},
  {q:"Which process involves storing information over long periods of time?",o:["Encoding", "Retrieval", "Recognition", "Storage"],a:3,e:"Storage refers to maintaining encoded information in memory systems for long periods."},
  {q:"The mental process used to evaluate possible solutions to a problem is called:",o:["Conditioning", "Reinforcement", "Problem solving", "Punishment"],a:2,e:"Problem solving involves cognitive processes used to analyze and resolve complex issues."},
  {q:"In cognitive psychology, mental shortcuts used to make quick judgments are known as:",o:["Conditioning", "Reinforcement", "Habituation", "Heuristics"],a:3,e:"Heuristics are mental shortcuts that simplify decision-making and judgment."},
  {q:"The ability to store information for a lifetime is a characteristic of which memory system?",o:["Short-term memory", "Sensory memory", "Long-term memory", "Working memory"],a:2,e:"Long-term memory has vast capacity and can retain information for very long periods, potentially throughout life."},
  {q:"Which psychologist developed the theory of psychoanalysis emphasizing unconscious mental processes and early childhood experiences?",o:["B.F. Skinner", "Jean Piaget", "Sigmund Freud", "Ivan Pavlov"],a:2,e:"Sigmund Freud developed psychoanalytic theory, emphasizing unconscious processes, early childhood experiences, and internal psychological conflicts."},
  {q:"A patient undergoing psychotherapy begins recalling painful childhood experiences that were previously forgotten but now influence current emotional problems. According to psychoanalytic theory, this process involves bringing material from which part of the mind into awareness?",o:["Conscious mind", "Preconscious mind", "Unconscious mind", "Sensory memory"],a:2,e:"Freud proposed that the unconscious mind stores repressed memories and impulses. Psychoanalysis attempts to bring these into conscious awareness."},
  {q:"In Freud’s structural model of personality, which component operates according to the pleasure principle and seeks immediate gratification of desires?",o:["Ego", "Superego", "Id", "Conscious mind"],a:2,e:"The id is the primitive component of personality driven by instinctual desires and operates according to the pleasure principle."},
  {q:"A person controls impulsive desires and behaves according to social rules and reality. Which component of Freud’s personality structure is primarily responsible for this regulation?",o:["Id", "Ego", "Superego", "Libido"],a:1,e:"The ego mediates between instinctual impulses of the id, moral standards of the superego, and external reality."},
  {q:"Which component of personality represents internalized moral standards and societal rules according to Freud’s theory?",o:["Id", "Libido", "Ego", "Superego"],a:3,e:"The superego represents internalized societal values and moral standards, guiding ethical behavior."},
  {q:"A patient unconsciously attributes their own unacceptable thoughts and feelings to another person. Which defense mechanism best explains this behavior?",o:["Projection", "Repression", "Denial", "Sublimation"],a:0,e:"Projection involves attributing one’s unacceptable thoughts or impulses to another person to reduce internal anxiety."},
  {q:"According to Freud, which psychosexual stage of development occurs during the first year of life and focuses on pleasure from oral activities such as sucking and feeding?",o:["Anal stage", "Phallic stage", "Oral stage", "Latency stage"],a:2,e:"The oral stage occurs from birth to about 18 months, where pleasure centers on oral activities."},
  {q:"A child between 3 and 6 years old develops unconscious attraction toward the opposite-sex parent and rivalry toward the same-sex parent. According to Freud, this phenomenon is known as:",o:["Electra complex", "Inferiority complex", "Identity crisis", "Oedipus complex"],a:3,e:"The Oedipus complex occurs during the phallic stage and involves unconscious desire for the opposite-sex parent."},
  {q:"Which defense mechanism involves pushing distressing thoughts or memories out of conscious awareness?",o:["Displacement", "Repression", "Projection", "Reaction formation"],a:1,e:"Repression is the unconscious exclusion of distressing thoughts or memories from conscious awareness."},
  {q:"A person who is angry with their supervisor instead expresses anger toward a family member at home. Which defense mechanism is demonstrated?",o:["Sublimation", "Displacement", "Denial", "Rationalization"],a:1,e:"Displacement redirects emotional impulses from a threatening target to a safer substitute."},
  {q:"In psychoanalysis, which method involves encouraging patients to verbalize all thoughts without censorship?",o:["Hypnosis", "Cognitive restructuring", "Free association", "Reinforcement"],a:2,e:"Free association encourages patients to express thoughts freely to reveal unconscious conflicts."},
  {q:"A patient unconsciously refuses to accept a painful reality such as a serious illness. Which defense mechanism is involved?",o:["Projection", "Sublimation", "Repression", "Denial"],a:3,e:"Denial involves refusing to accept external reality because it is too distressing."},
  {q:"According to Freud’s psychosexual theory, which stage is associated with toilet training and development of self-control?",o:["Oral stage", "Phallic stage", "Anal stage", "Latency stage"],a:2,e:"The anal stage (1–3 years) centers on bowel control and development of self-discipline."},
  {q:"A person channels aggressive impulses into socially acceptable activities such as competitive sports. Which defense mechanism does this illustrate?",o:["Denial", "Repression", "Regression", "Sublimation"],a:3,e:"Sublimation redirects unacceptable impulses into constructive activities."},
  {q:"Which psychosexual stage is characterized by a relative calm period when sexual impulses are largely suppressed and children focus on school and social development?",o:["Oral stage", "Phallic stage", "Latency stage", "Genital stage"],a:2,e:"The latency stage (6 years to puberty) is marked by reduced sexual impulses and focus on learning and socialization."},
  {q:"A patient justifies a failure in an examination by claiming the exam was unfair rather than accepting personal responsibility. Which defense mechanism is illustrated?",o:["Projection", "Repression", "Displacement", "Rationalization"],a:3,e:"Rationalization involves creating logical explanations to justify failures or unacceptable behavior."},
  {q:"Which stage of Freud’s psychosexual development occurs during adolescence and is associated with mature sexual relationships?",o:["Latency stage", "Oral stage", "Genital stage", "Anal stage"],a:2,e:"The genital stage begins at puberty and involves mature sexual relationships and reproduction."},
  {q:"A stressed adult begins behaving in a childish manner during emotional conflict. Which defense mechanism is demonstrated?",o:["Projection", "Denial", "Sublimation", "Regression"],a:3,e:"Regression involves reverting to behaviors typical of an earlier developmental stage during stress."},
  {q:"According to Freud’s theory, the energy that drives instinctual behavior and sexual impulses is called:",o:["Ego", "Superego", "Id", "Libido"],a:3,e:"Libido refers to psychic energy associated with life instincts and sexual drives."},
  {q:"In psychoanalytic therapy, the patient may unconsciously redirect feelings toward the therapist that were originally directed toward significant people in their past. This phenomenon is called:",o:["Countertransference", "Transference", "Projection", "Rationalization"],a:1,e:"Transference occurs when feelings related to past relationships are projected onto the therapist."},
  {q:"The therapist’s emotional reactions to a patient during psychoanalysis are referred to as:",o:["Transference", "Projection", "Countertransference", "Repression"],a:2,e:"Countertransference refers to the therapist’s emotional responses toward the patient."},
  {q:"Which level of consciousness contains information that is not currently in awareness but can easily be retrieved?",o:["Unconscious", "Preconscious", "Id", "Superego"],a:1,e:"The preconscious stores information that is not currently conscious but can be readily accessed."},
  {q:"A patient unconsciously converts emotional stress into physical symptoms such as paralysis without an organic cause. In psychoanalytic terms, this process is known as:",o:["Projection", "Sublimation", "Conversion", "Rationalization"],a:2,e:"Conversion involves transforming psychological conflict into physical symptoms."},
  {q:"According to psychoanalytic theory, which personality component acts as the moral conscience of the individual?",o:["Id", "Ego", "Libido", "Superego"],a:3,e:"The superego represents internalized moral standards and evaluates behavior as right or wrong."},
  {q:"A person refuses to acknowledge feelings of anger toward a loved one and instead expresses exaggerated affection toward them. Which defense mechanism explains this behavior?",o:["Repression", "Projection", "Reaction formation", "Denial"],a:2,e:"Reaction formation involves behaving opposite to true feelings to reduce anxiety."},
  {q:"According to Freud, personality development is largely completed by approximately which age?",o:["3 years", "12 years", "5 years", "18 years"],a:2,e:"Freud believed major aspects of personality are established by about age five."},
  {q:"Which defense mechanism involves returning to behaviors typical of an earlier developmental stage?",o:["Projection", "Sublimation", "Regression", "Rationalization"],a:2,e:"Regression occurs when individuals revert to earlier developmental behaviors during stress."},
  {q:"According to psychoanalysis, dreams represent expressions of:",o:["Conscious reasoning", "Logical thinking", "Unconscious wishes and conflicts", "Learned behavior"],a:2,e:"Freud considered dreams expressions of unconscious desires and unresolved conflicts."},
  {q:"The symbolic meaning of a dream as interpreted by psychoanalysis is called:",o:["Manifest content", "Conscious content", "Literal content", "Latent content"],a:3,e:"Latent content represents the hidden psychological meaning of dreams."},
  {q:"In Freud’s theory, the realistic mediator between instinctual drives and moral standards is the:",o:["Id", "Ego", "Superego", "Libido"],a:1,e:"The ego balances the demands of the id, superego, and external reality."},
  {q:"A person unconsciously forgets a traumatic childhood experience. Which defense mechanism explains this forgetting?",o:["Projection", "Sublimation", "Repression", "Displacement"],a:2,e:"Repression pushes painful memories out of conscious awareness."},
  {q:"In psychoanalytic theory, which instinct is associated with aggression and destructive behavior?",o:["Life instinct", "Libido", "Ego instinct", "Death instinct"],a:3,e:"Freud proposed the death instinct (Thanatos), responsible for aggression and destructive impulses."},
  {q:"The part of the mind containing thoughts and perceptions currently in awareness is called the:",o:["Conscious mind", "Preconscious", "Unconscious", "Subconscious"],a:0,e:"The conscious mind contains thoughts and perceptions currently in awareness."},
  {q:"According to psychoanalysis, anxiety arises when there is conflict between which personality components?",o:["Conscious and unconscious", "Behavior and cognition", "Id, ego, and superego", "Memory and perception"],a:2,e:"Anxiety arises when the ego struggles to balance the demands of the id and superego."},
  {q:"Which psychoanalytic concept refers to redirecting unacceptable impulses toward a safer substitute target?",o:["Denial", "Sublimation", "Repression", "Displacement"],a:3,e:"Displacement redirects emotions from a threatening object to a safer target."},
  {q:"The process of bringing unconscious conflicts into conscious awareness during therapy is called:",o:["Conditioning", "Reinforcement", "Habituation", "Psychoanalysis"],a:3,e:"Psychoanalysis aims to reveal unconscious conflicts and motivations."},
  {q:"Which defense mechanism involves refusing to accept reality despite clear evidence?",o:["Rationalization", "Projection", "Sublimation", "Denial"],a:3,e:"Denial involves rejecting external reality to avoid psychological distress."},
  {q:"In psychoanalysis, the observable storyline of a dream is known as the:",o:["Latent content", "Hidden content", "Manifest content", "Symbolic content"],a:2,e:"Manifest content is the literal storyline of the dream as remembered."},
  {q:"Which personality component operates entirely in the unconscious according to Freud?",o:["Ego", "Superego", "Conscious mind", "Id"],a:3,e:"The id functions entirely in the unconscious and is driven by instinctual impulses."},
  {q:"Psychoanalytic therapy primarily focuses on understanding:",o:["Reflex behaviors", "Genetic inheritance", "Sensory perception", "Unconscious motivations and conflicts"],a:3,e:"Psychoanalysis focuses on uncovering unconscious motivations and conflicts influencing behavior."},
  {q:"Which psychologist proposed the psychosocial theory of development consisting of eight stages across the lifespan?",o:["Sigmund Freud", "B.F. Skinner", "Jean Piaget", "Erik Erikson"],a:3,e:"Erik Erikson proposed the psychosocial theory of development consisting of eight stages across the lifespan, each involving a psychosocial crisis."},
  {q:"According to Erikson, the first stage of psychosocial development occurring during infancy involves which psychosocial conflict?",o:["Trust vs mistrust", "Autonomy vs shame and doubt", "Initiative vs guilt", "Identity vs role confusion"],a:0,e:"Trust vs mistrust occurs in infancy. Consistent caregiving fosters trust; inconsistent care leads to mistrust."},
  {q:"A toddler begins to assert independence by choosing clothes and attempting tasks alone. According to Erikson’s theory, which psychosocial stage is being experienced?",o:["Initiative vs guilt", "Industry vs inferiority", "Autonomy vs shame and doubt", "Identity vs role confusion"],a:2,e:"Autonomy vs shame and doubt occurs between ages 1–3 when toddlers develop independence and self-control."},
  {q:"A preschool child begins to initiate play activities and explore new experiences. Which psychosocial conflict described by Erikson occurs during this stage?",o:["Industry vs inferiority", "Initiative vs guilt", "Autonomy vs shame", "Trust vs mistrust"],a:1,e:"Initiative vs guilt occurs between ages 3–6 when children begin initiating activities and exploring their environment."},
  {q:"According to Erikson, which stage occurs during school-age years when children focus on developing competence in academic and social activities?",o:["Initiative vs guilt", "Identity vs role confusion", "Industry vs inferiority", "Generativity vs stagnation"],a:2,e:"Industry vs inferiority occurs during school age when children develop competence through learning and achievement."},
  {q:"A 16-year-old adolescent is exploring career goals, beliefs, and personal values. According to Erikson, which psychosocial conflict is being resolved?",o:["Intimacy vs isolation", "Initiative vs guilt", "Identity vs role confusion", "Industry vs inferiority"],a:2,e:"Identity vs role confusion occurs in adolescence as individuals develop a stable personal identity."},
  {q:"Which psychosocial stage of Erikson’s theory involves forming close emotional relationships during young adulthood?",o:["Identity vs role confusion", "Generativity vs stagnation", "Integrity vs despair", "Intimacy vs isolation"],a:3,e:"Intimacy vs isolation occurs during young adulthood when individuals seek deep emotional relationships."},
  {q:"According to Erikson, the stage during middle adulthood in which individuals focus on contributing to society and supporting the next generation is called:",o:["Intimacy vs isolation", "Integrity vs despair", "Generativity vs stagnation", "Identity vs role confusion"],a:2,e:"Generativity vs stagnation involves contributing to society and guiding the next generation."},
  {q:"In Erikson’s final stage of psychosocial development, older adults reflect on their life and feel either satisfaction or regret. What is this stage called?",o:["Generativity vs stagnation", "Identity vs role confusion", "Integrity vs despair", "Intimacy vs isolation"],a:2,e:"Integrity vs despair occurs in late adulthood when individuals evaluate their life experiences."},
  {q:"In Erikson’s psychosocial theory, successful resolution of the trust vs mistrust stage leads to development of which virtue?",o:["Will", "Purpose", "Fidelity", "Hope"],a:3,e:"The virtue of hope develops when infants successfully develop trust in caregivers."},
  {q:"According to Erikson, the virtue developed after successfully resolving identity vs role confusion is:",o:["Love", "Hope", "Fidelity", "Care"],a:2,e:"Fidelity reflects loyalty and commitment to one’s identity and beliefs."},
  {q:"Which virtue is developed when the intimacy vs isolation stage is successfully resolved?",o:["Hope", "Love", "Will", "Wisdom"],a:1,e:"Love represents the ability to form deep emotional bonds and relationships."},
  {q:"During middle adulthood, individuals who successfully resolve generativity vs stagnation develop which virtue?",o:["Wisdom", "Love", "Care", "Hope"],a:2,e:"Care represents concern for guiding the next generation and contributing to society."},
  {q:"According to Erikson, the virtue associated with successful resolution of the final stage of development is:",o:["Love", "Wisdom", "Hope", "Purpose"],a:1,e:"Wisdom develops when individuals reflect on life with acceptance and integrity."},
  {q:"A child who is repeatedly criticized for attempting independent tasks begins to doubt their abilities. Which Eriksonian conflict is being negatively resolved?",o:["Initiative vs guilt", "Industry vs inferiority", "Autonomy vs shame and doubt", "Identity vs role confusion"],a:2,e:"Excessive criticism during toddlerhood leads to shame and doubt instead of autonomy."},
  {q:"A middle-aged adult feels unproductive and self-absorbed. Which Eriksonian crisis is most likely unresolved?",o:["Intimacy vs isolation", "Generativity vs stagnation", "Identity vs role confusion", "Industry vs inferiority"],a:1,e:"Failure to achieve generativity results in stagnation and lack of societal contribution."},
  {q:"Erikson’s psychosocial theory differs from Freud’s psychosexual theory primarily because it:",o:["Focuses only on childhood", "Rejects all unconscious processes", "Emphasizes conditioning", "Emphasizes social relationships throughout the entire lifespan"],a:3,e:"Erikson emphasized psychosocial development across the entire lifespan rather than only early childhood."},
  {q:"A young adult avoids forming close relationships due to fear of rejection. According to Erikson, failure to resolve which stage may explain this?",o:["Identity vs role confusion", "Generativity vs stagnation", "Intimacy vs isolation", "Industry vs inferiority"],a:2,e:"Failure to achieve intimacy results in isolation and difficulty forming meaningful relationships."},
  {q:"According to Erikson, the virtue of “will” develops when which stage is successfully resolved?",o:["Trust vs mistrust", "Initiative vs guilt", "Industry vs inferiority", "Autonomy vs shame and doubt"],a:3,e:"Successful autonomy leads to the virtue of will, reflecting independence and self-control."},
  {q:"Erikson believed that personality development occurs:",o:["Only during childhood", "Only during adolescence", "Only during adulthood", "Throughout the entire lifespan"],a:3,e:"Erikson proposed that development continues throughout life across eight psychosocial stages."},
  {q:"Which psychologist is most closely associated with the development of social learning theory?",o:["Jean Piaget", "B.F. Skinner", "Sigmund Freud", "Albert Bandura"],a:3,e:"Albert Bandura developed social learning theory, proposing that individuals learn new behaviors through observation and imitation of others. His work integrated behavioral principles with cognitive processes such as attention, memory, and motivation."},
  {q:"A child watches an older sibling receive praise for completing homework and then begins completing homework regularly as well. According to social learning theory, which process explains this behavior?",o:["Vicarious reinforcement", "Classical conditioning", "Habituation", "Punishment"],a:0,e:"Vicarious reinforcement occurs when individuals observe another person receiving rewards for a behavior and are therefore more likely to imitate that behavior themselves. This indirect reinforcement influences learning even without direct reward."},
  {q:"In social learning theory, the person whose behavior is observed and imitated is known as the:",o:["Stimulus", "Model", "Reinforcer", "Observer"],a:1,e:"A model is an individual whose behavior is observed and potentially imitated by others. Models may include parents, teachers, peers, or media figures who influence learning through their actions."},
  {q:"According to Bandura, which cognitive process in observational learning involves focusing on the behavior of the model?",o:["Motivation", "Retention", "Attention", "Reproduction"],a:2,e:"Attention is the first step in observational learning. Individuals must notice and pay attention to the model’s behavior before it can be learned or imitated."},
  {q:"A medical student observes a senior physician demonstrating a clinical procedure and later performs the same procedure during training. Which stage of observational learning is represented when the student actually performs the behavior?",o:["Attention", "Reproduction", "Retention", "Reinforcement"],a:1,e:"Reproduction refers to the ability to perform the behavior that has been observed and stored in memory. After paying attention and retaining the behavior, individuals reproduce it through action."},
  {q:"According to social learning theory, the process of remembering observed behavior so it can be performed later is called:",o:["Motivation", "Attention", "Retention", "Conditioning"],a:2,e:"Retention involves storing observed information in memory. Without retention, the individual cannot reproduce the behavior even if attention was initially given."},
  {q:"A child refuses to engage in misbehavior after seeing another child punished for the same behavior. Which concept best explains this learning process?",o:["Vicarious punishment", "Classical conditioning", "Insight learning", "Habituation"],a:0,e:"Vicarious punishment occurs when observing someone else being punished decreases the likelihood that the observer will perform the same behavior."},
  {q:"Which concept in Bandura’s theory refers to an individual’s belief in their own ability to successfully perform a task?",o:["Reinforcement", "Self-efficacy", "Conditioning", "Extinction"],a:1,e:"Self-efficacy refers to confidence in one’s ability to perform behaviors successfully. Higher self-efficacy increases persistence, motivation, and performance."},
  {q:"According to Bandura, learning occurs through interaction between personal factors, behavior, and the environment. This concept is known as:",o:["Reciprocal determinism", "Conditioning", "Reinforcement", "Instinct theory"],a:0,e:"Reciprocal determinism describes the dynamic interaction between cognitive factors, behavior, and environmental influences. Each component influences and is influenced by the others."},
  {q:"A child imitates polite manners after observing parents consistently using respectful language. Which social learning principle explains this behavior?",o:["Classical conditioning", "Modeling", "Punishment", "Extinction"],a:1,e:"Modeling refers to learning behaviors by observing others and imitating them. Parents often serve as powerful behavioral models for children."},
  {q:"Which famous experiment demonstrated that children imitate aggressive behaviors observed in adults?",o:["Stanford prison experiment", "Pavlov’s dog experiment", "Bobo doll experiment", "Skinner box experiment"],a:2,e:"Bandura’s Bobo doll experiment showed that children exposed to aggressive adult models were more likely to imitate those aggressive behaviors during play."},
  {q:"In social learning theory, which factor determines whether an observed behavior will actually be imitated?",o:["Reinforcement", "Motivation", "Instinct", "Conditioning"],a:1,e:"Motivation determines whether a learned behavior will be performed. Individuals may imitate behaviors if they expect rewards or avoid punishment."},
  {q:"A trainee doctor becomes more confident in performing procedures after watching experienced physicians perform them successfully. Which concept explains this increased confidence?",o:["Self-efficacy", "Classical conditioning", "Habituation", "Punishment"],a:0,e:"Self-efficacy develops through mastery experiences, observing successful models, and encouragement. It strongly influences motivation and performance."},
  {q:"Which of the following is NOT one of Bandura’s four processes required for observational learning?",o:["Attention", "Retention", "Motivation", "Instinct"],a:3,e:"Observational learning requires attention, retention, reproduction, and motivation. Instinct is not part of the social learning process."},
  {q:"A child studies harder after noticing classmates receiving rewards for good academic performance. Which concept explains this behavior?",o:["Vicarious reinforcement", "Extinction", "Classical conditioning", "Punishment"],a:0,e:"Observing others being rewarded for behavior increases the likelihood that the observer will perform the same behavior."},
  {q:"Which cognitive process in social learning theory allows an individual to mentally store observed behavior for later imitation?",o:["Attention", "Retention", "Reproduction", "Motivation"],a:1,e:"Retention refers to encoding and storing observed behavior in memory. This stored representation allows later reproduction of the behavior."},
  {q:"A student begins practicing public speaking after observing peers successfully giving presentations and receiving praise. Which learning principle best explains this?",o:["Modeling", "Habituation", "Conditioning", "Extinction"],a:0,e:"Modeling occurs when individuals imitate behaviors observed in others, particularly when those behaviors are rewarded or admired."},
  {q:"Social learning theory differs from traditional behaviorism because it emphasizes:",o:["Cognitive processes in learning", "Reflex responses", "Genetic inheritance of behavior", "Pure conditioning"],a:0,e:"Unlike strict behaviorism, social learning theory emphasizes mental processes such as attention, expectations, and memory in learning."},
  {q:"In social learning theory, observing another person being punished for a behavior reduces the likelihood of performing that behavior. This is known as:",o:["Classical conditioning", "Vicarious punishment", "Extinction", "Habituation"],a:1,e:"Vicarious punishment occurs when observing punishment experienced by others discourages the observer from engaging in the same behavior."},
  {q:"According to Bandura’s theory, learning can occur even when behavior is not immediately performed. This concept is referred to as:",o:["Latent observational learning", "Reinforcement learning", "Instinctive learning", "Reflex learning"],a:0,e:"Social learning theory suggests that individuals may acquire knowledge by observing others without immediately demonstrating the behavior. Performance may occur later when motivation is present."},
  {q:"A physician informs a patient about a chronic illness diagnosis using simple language, maintains eye contact, and allows time for questions. Which communication principle is being demonstrated?",o:["Therapeutic communication", "Punitive communication", "Directive communication", "Defensive communication"],a:0,e:"Therapeutic communication involves using empathy, clarity, and supportive dialogue to help patients understand their condition and express concerns. It promotes trust and improves patient–doctor relationships."},
  {q:"A doctor begins a consultation by asking open-ended questions such as “Can you tell me what concerns brought you here today?” Which communication technique is being used?",o:["Closed questioning", "Leading questioning", "Open-ended questioning", "Confrontation"],a:2,e:"Open-ended questions encourage patients to describe their concerns in their own words. This approach improves information gathering and builds rapport during clinical interviews."},
  {q:"When delivering bad news to a patient, which communication protocol is widely recommended in medical practice?",o:["ABCD protocol", "SPIKES protocol", "SOAP method", "DSM protocol"],a:1,e:"The SPIKES protocol is a structured method for breaking bad news. It includes Setting, Perception, Invitation, Knowledge, Empathy, and Strategy/Summary."},
  {q:"A physician delivering bad news first ensures privacy, sits at eye level with the patient, and minimizes interruptions. Which step of the SPIKES protocol does this represent?",o:["Knowledge", "Setting", "Invitation", "Strategy"],a:1,e:"The “Setting” step involves creating a private and comfortable environment before delivering bad news. This helps ensure emotional support and respectful communication."},
  {q:"A patient becomes silent and tearful after hearing a cancer diagnosis. The physician responds by saying, “I can see this is very difficult news.” Which communication skill is being demonstrated?",o:["Confrontation", "Empathy", "Persuasion", "Reassurance"],a:1,e:"Empathy involves recognizing and acknowledging a patient’s emotional response. Expressing empathy helps patients feel understood and supported during distressing situations."},
  {q:"During counseling, a clinician summarizes the patient’s concerns and repeats them back to confirm understanding. Which communication technique is this?",o:["Reflection and summarizing", "Closed questioning", "Argumentation", "Advice giving"],a:0,e:"Reflection and summarizing ensure that the clinician has correctly understood the patient’s message. It also reassures the patient that their concerns are being heard."},
  {q:"Which counseling approach focuses on helping individuals resolve ambivalence and strengthen motivation for behavioral change?",o:["Psychoanalysis", "Motivational interviewing", "Classical conditioning", "Behavior modification"],a:1,e:"Motivational interviewing is a counseling method used to promote behavior change by exploring and resolving ambivalence, often used in addiction or lifestyle modification."},
  {q:"A physician asks a patient if they would like detailed information about their diagnosis before explaining the condition. Which step of SPIKES does this represent?",o:["Invitation", "Knowledge", "Empathy", "Strategy"],a:0,e:"The “Invitation” step involves asking the patient how much information they wish to receive about their condition."},
  {q:"A patient expresses anger after hearing bad news. The physician allows the patient to speak without interruption and acknowledges their feelings. Which counseling skill is demonstrated?",o:["Active listening", "Confrontation", "Persuasion", "Advice giving"],a:0,e:"Active listening involves paying full attention to the patient’s words and emotions without interruption. It improves understanding and strengthens therapeutic relationships."},
  {q:"Which communication barrier occurs when a doctor uses complex medical terminology that the patient cannot understand?",o:["Psychological barrier", "Language barrier", "Emotional barrier", "Cultural barrier"],a:1,e:"Using technical medical language can prevent effective understanding. Simplifying explanations improves patient comprehension and adherence."},
  {q:"A doctor reassures a patient by saying, “We will work together to manage this condition and I will support you through treatment.” Which counseling principle is demonstrated?",o:["Therapeutic alliance", "Punishment", "Avoidance", "Denial"],a:0,e:"Therapeutic alliance refers to the collaborative relationship between clinician and patient. It enhances trust and treatment adherence."},
  {q:"During counseling, the doctor focuses on understanding the patient’s perspective and encourages expression of feelings. Which counseling approach is being used?",o:["Patient-centered counseling", "Directive counseling", "Authoritarian communication", "Confrontational therapy"],a:0,e:"Patient-centered counseling prioritizes understanding the patient’s experiences, values, and concerns, improving satisfaction and treatment outcomes."},
  {q:"A physician delivering bad news pauses frequently to check whether the patient understands the information. Which communication skill is being applied?",o:["Checking understanding", "Argumentation", "Persuasion", "Avoidance"],a:0,e:"Checking understanding ensures the patient correctly comprehends information. This reduces confusion and helps guide further discussion."},
  {q:"Which communication skill involves encouraging the patient to continue speaking through verbal cues like “I see” or “Go on”?",o:["Facilitation", "Confrontation", "Persuasion", "Reprimanding"],a:0,e:"Facilitation uses brief prompts to encourage patients to continue expressing thoughts or emotions without interrupting their narrative."},
  {q:"A patient asks the doctor, “Am I going to die soon?” after receiving a serious diagnosis. The doctor responds honestly but sensitively. Which communication principle is applied?",o:["Truth-telling with compassion", "Avoidance", "Deception", "Persuasion"],a:0,e:"Ethical communication requires honesty while maintaining compassion. Patients generally prefer truthful information delivered sensitively."},
  {q:"In counseling, maintaining eye contact, nodding, and appropriate facial expressions are examples of:",o:["Nonverbal communication", "Punishment", "Conditioning", "Persuasion"],a:0,e:"Nonverbal communication conveys empathy, attention, and understanding. It significantly influences the effectiveness of clinician–patient interactions."},
  {q:"A physician encourages a patient to describe their concerns without interruption and avoids judging their statements. Which counseling technique is this?",o:["Nonjudgmental attitude", "Confrontation", "Persuasion", "Advice giving"],a:0,e:"Maintaining a nonjudgmental attitude allows patients to speak freely and openly about sensitive issues."},
  {q:"A doctor explains a diagnosis using diagrams and simple language to ensure understanding. Which informational care principle is demonstrated?",o:["Health education", "Persuasion", "Confrontation", "Denial"],a:0,e:"Health education involves providing clear, understandable information about diseases and treatments to support informed decision-making."},
  {q:"During a consultation, the physician summarizes the treatment plan and asks the patient to repeat the instructions to confirm understanding. Which technique is used?",o:["Teach-back method", "Persuasion", "Conditioning", "Punishment"],a:0,e:"The teach-back method checks patient understanding by asking them to explain information in their own words."},
  {q:"A patient becomes distressed while hearing about a terminal illness diagnosis. Which initial physician response is most appropriate?",o:["Ignore emotions and continue explanation", "Provide immediate reassurance only", "Acknowledge emotions and provide support", "Change the topic"],a:2,e:"Acknowledging the patient’s emotions is a key step in breaking bad news. Emotional support helps patients process difficult information."},
  {q:"Counseling primarily aims to:",o:["Help patients understand and cope with problems", "Provide punishment for unhealthy behavior", "Avoid discussing emotional issues", "Enforce medical decisions"],a:0,e:"Counseling helps individuals understand problems, develop coping strategies, and make informed decisions regarding their health."},
  {q:"A doctor pauses after explaining a diagnosis to allow the patient time to process the information. Which communication principle is demonstrated?",o:["Silence as therapeutic tool", "Confrontation", "Persuasion", "Avoidance"],a:0,e:"Therapeutic silence allows patients to reflect and express emotions. It shows respect and patience during emotionally difficult discussions."},
  {q:"A patient-centered communication style improves clinical outcomes primarily because it:",o:["Enhances trust and adherence", "Reduces consultation time only", "Avoids patient participation", "Prevents emotional discussion"],a:0,e:"Patient-centered communication improves trust, satisfaction, and adherence to treatment plans."},
  {q:"A clinician asks, “What concerns you most about your illness?” Which communication skill is being used?",o:["Exploring patient concerns", "Confrontation", "Persuasion", "Instruction"],a:0,e:"Exploring concerns helps identify patient priorities and emotional needs, guiding effective counseling."},
  {q:"Breaking bad news effectively requires which key ethical principle?",o:["Respect for patient autonomy", "Avoidance of discussion", "Concealment of diagnosis", "Delayed communication"],a:0,e:"Respecting patient autonomy involves providing truthful information so patients can make informed decisions about their care."},
  {q:"During counseling, the doctor paraphrases the patient’s statements to clarify meaning. Which skill is this?",o:["Paraphrasing", "Persuasion", "Punishment", "Confrontation"],a:0,e:"Paraphrasing involves restating the patient’s message in the clinician’s own words to confirm understanding."},
  {q:"A patient expresses fear after hearing about surgery. The doctor responds by exploring the patient’s fears in detail. Which counseling strategy is applied?",o:["Exploring emotions", "Avoidance", "Persuasion", "Denial"],a:0,e:"Exploring emotions helps identify patient fears and concerns, allowing supportive and tailored counseling."},
  {q:"Which component of the SPIKES protocol involves providing information about diagnosis and prognosis?",o:["Knowledge", "Invitation", "Setting", "Empathy"],a:0,e:"The “Knowledge” step involves delivering medical information clearly and gradually to the patient."},
  {q:"Effective doctor–patient communication primarily improves:",o:["Patient satisfaction and treatment adherence", "Only physician authority", "Hospital profits", "Diagnostic imaging accuracy"],a:0,e:"Good communication improves patient satisfaction, adherence to treatment, and overall clinical outcomes."},
  {q:"Which communication approach encourages patients to actively participate in decision-making about their treatment?",o:["Shared decision-making", "Authoritarian communication", "Paternalistic approach", "Directive counseling"],a:0,e:"Shared decision-making involves collaboration between doctor and patient, ensuring patient preferences are considered in treatment decisions."},
  {q:"A doctor explains treatment options and encourages the patient to express preferences. Which ethical principle is demonstrated?",o:["Autonomy", "Beneficence only", "Nonmaleficence only", "Justice"],a:0,e:"Respecting autonomy means allowing patients to make informed decisions about their healthcare."},
  {q:"A patient becomes overwhelmed after hearing a diagnosis. Which response by the doctor best demonstrates empathy?",o:["“I understand this must be very difficult for you.”", "“There is nothing to worry about.”", "“You should not feel upset.”", "“Let’s discuss something else.”"],a:0,e:"Empathetic responses acknowledge the patient’s emotions and validate their feelings."},
  {q:"Which communication strategy improves understanding when explaining complex medical information?",o:["Using simple language and visual aids", "Using technical terminology", "Providing minimal information", "Avoiding patient questions"],a:0,e:"Simplifying language and using visual aids improve patient comprehension and reduce confusion."},
  {q:"A physician checks if the patient understands instructions before ending the consultation. Which counseling goal does this achieve?",o:["Ensuring informed understanding", "Increasing consultation length", "Limiting patient participation", "Avoiding responsibility"],a:0,e:"Confirming understanding ensures patients know how to follow treatment plans and reduces medical errors."},
  {q:"Which communication skill involves repeating a patient’s key message in concise form?",o:["Summarizing", "Conditioning", "Persuasion", "Confrontation"],a:0,e:"Summarizing helps clarify discussion and ensures mutual understanding before moving to the next topic."},
  {q:"A patient becomes angry during consultation. The doctor responds calmly and listens carefully. Which skill is demonstrated?",o:["Emotional regulation and empathy", "Punishment", "Avoidance", "Argumentation"],a:0,e:"Maintaining calmness and empathy during emotional situations supports effective communication and conflict resolution."},
  {q:"Informational care in healthcare primarily refers to:",o:["Providing accurate and understandable health information", "Limiting information given to patients", "Avoiding emotional discussion", "Persuading patients to follow treatment"],a:0,e:"Informational care ensures patients receive clear, relevant information to understand their health conditions and treatment options."},
  {q:"A patient asks many questions after receiving a diagnosis. The doctor answers patiently and encourages discussion. Which communication principle is demonstrated?",o:["Encouraging patient participation", "Avoidance", "Persuasion", "Punishment"],a:0,e:"Encouraging questions empowers patients and improves understanding of their health condition."},
  {q:"Which communication technique helps build trust between physician and patient?",o:["Empathy and active listening", "Dominant communication", "Minimal interaction", "Avoidance"],a:0,e:"Empathy and active listening strengthen trust and improve therapeutic relationships."},
  {q:"In clinical counseling, the primary goal of breaking bad news appropriately is to:",o:["Help patients understand and emotionally cope with difficult information", "Avoid discussing prognosis", "Minimize patient involvement", "Deliver information quickly"],a:0,e:"Effective delivery of bad news allows patients to understand their condition while providing emotional support and guidance for future decisions."},
];